INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-de09bf8b-moex-00169', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '富二代甲受友人乙邀約，至丙開設之娛樂公司進行博弈消費，一晚豪賭後輸了新臺幣（下同）500 萬元，甲遂簽立借據並簽發500萬元本票於丙；其後，丙將該債權、借據及本票以400萬元讓售 於債務催收公司丁。事後丁提示借據及本票向甲催收時，甲反控遭乙、丙二人詐賭，認為「賭債 非債」，本票債權不存在。下列敘述何者正確？', '["丙讓與債權於丁，因丙未通知甲，故對甲不生債權讓與效力", "甲所簽立之借據，因無借款之真意，故甲得撤銷該借據", "甲所簽發之本票，因本票債權違反公序良俗無效，故該本票亦為無效", "丙以無效之債權讓售於丁，須對丁負權利瑕疵擔保之責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00170', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '下列何者為要約？', '["商品在報章雜誌廣告", "量販店寄送之價目表", "小吃店標示有價格之「請自取」的小菜", "車展中標示價格展示之汽車"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00171', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '關於租賃之敘述，下列何者錯誤？', '["租賃關係存續中，因不可歸責於出租人及承租人之事由，致租賃物一部滅失時，承租人得按滅 失之部分，請求減少租金", "承租人因病住院，致不能為租賃物全部之使用收益時，不得因此免其支付租金之義務", "承租人租用A屋，與出租人約定租金為每個月新臺幣1萬元，且按月於月初支付。承租人遲付 租金之總額已達2個月之租額時，出租人得逕終止契約", "租賃物之修繕，得約定由出租人與承租人平均負擔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00172', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '關於添附之敘述，下列何者錯誤？', '["加工於他人之動產者，其加工物之所有權屬於加工人。但因材料之價值顯逾加工所增之價值者， 其加工物之所有權屬於材料所有人", "動產與他人之動產附合，非毀損不能分離或分離需費過鉅者，若無其他條件，各動產所有人按 其動產附合時之價值，共有合成物", "動產與他人之動產混合，不能識別或識別需費過鉅者，若無其他條件，各動產所有人按其動產 混合時之價值，共有混合物", "動產因附合而為不動產之重要成分者，不動產所有權人取得動產所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00173', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲、乙、丙三人分別共有A地，應有部分各三分之一，並經登記於土地登記簿。甲以其應有部分 設定普通抵押權於丁。丙請求分割A地。下列敘述何者錯誤？', '["丁同意A地之分割者，其抵押權移存於甲因分割而分得之部分", "丁經通知A地分割者，其抵押權移存於甲因分割而分得之部分", "丁經共有人告知訴訟而未參加者，其抵押權移存於甲因分割而分得之部分", "丁已參加共有物分割訴訟，其抵押權移存於甲因分割而分得之部分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00174', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲經營健身房，因疫情致財務陷於困境，故以其母留下之多條珍珠項鍊作為擔保品，向乙借款。 下列敘述何者錯誤？', '["乙讓與該債權於第三人，該動產質權亦隨之移轉", "乙死亡，其繼承人取得該動產質權", "甲乙間得以占有改定方式設質於乙", "該動產質權之擔保範圍，包含原債權及利息"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00175', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲駕駛愛車至乙洗車場洗車，洗車機正常運作係以輸送帶之滾筒帶動車輛前輪進入洗車機，惟甲 之車輛於洗車過程中操作致脫軌受損。下列敘述何者正確？', '["洗車場屬於民法第191條之3危險活動責任", "依軌道行駛之動力車輛，不適用民法侵權行為之賠償規定", "若甲未遵循洗車場之指示，致車輛以自身動力脫離直線軌道，應自負其責", "依民法規定，乙洗車場應負無過失責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00176', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲於購物網站購買一台吸塵器，並於網路上付清全額貨款。該購物網站將吸塵器寄送至甲所住之 大樓，由大樓管理員代為簽收。此行為屬於下列何種交付？', '["現實交付", "簡易交付", "占有改定", "指示交付"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00177', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲已離婚，有一子乙。嗣後，甲與丙女結婚，乙與丁女結婚。丙女與丁女關係為何？', '["無親屬關係", "一親等直系姻親", "一親等直系血親", "二親等直系姻親"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00178', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲、乙之婚姻被法院判決無效確定。甲乙現存婚後財產之價值計算，以何時為準？', '["結婚登記時", "起訴時", "判決確定時", "法定財產制關係消滅時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
